extra.modelCss:
/* Código bonito (pronto para highlight) */

:root {
  --code-bg: #0d1117;
  --code-panel: #0f172a;
  --code-text: #c9d1d9;
  --code-border: rgba(255, 255, 255, 0.10);
  --code-muted: #8b949e;
  --code-keyword: #c586c0;
  --code-string: #98c379;
  --code-number: #d19a66;
  --code-fn: #61afef;
  --code-type: #4ec9b0;
  --code-operator: #56b6c2;
}

/* Inline code */
.prose code {
  font-family: ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, "Liberation Mono", "Courier New", monospace;
  font-size: 0.95em;
  padding: 0.12em 0.35em;
  border-radius: 8px;
  border: 1px solid var(--code-border);
  background: rgba(255, 255, 255, 0.04);
}

/* Code block wrapper (opcional) */
.codeblock {
  position: relative;
  border: 1px solid var(--code-border);
  border-radius: 14px;
  background: var(--code-panel);
}

.codeblock pre {
  margin: 0;
  padding: 14px;
  overflow-x: auto;
  max-width: 100%;
  -webkit-overflow-scrolling: touch;
}

.codeblock pre code {
  display: block;
  color: var(--code-text);
  font-family: ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, "Liberation Mono", "Courier New", monospace;
  font-size: 0.95rem;
  line-height: 1.55;
  white-space: pre;
}

/* Botão copiar (CSS pronto) */
.codeblock__copy {
  position: absolute;
  top: 10px;
  right: 10px;
  padding: 8px 10px;
  border-radius: 10px;
  border: 1px solid var(--code-border);
  background: rgba(255, 255, 255, 0.06);
  color: var(--code-text);
  cursor: pointer;
}

.codeblock__copy:focus-visible {
  outline: 3px solid #60a5fa;
  outline-offset: 3px;
}

/* Token classes (para quando você integrar highlight) */
.token.comment { color: var(--code-muted); }
.token.keyword { color: var(--code-keyword); }
.token.string { color: var(--code-string); }
.token.number { color: var(--code-number); }
.token.function { color: var(--code-fn); }
.token.class-name { color: var(--code-type); }
.token.operator { color: var(--code-operator); }
